    public override ModelExpression VisitCondition([NotNull] DdxParser.ConditionContext context)
    {
      if (context.SYM_LP() != null && context.SYM_RP() != null)
      {
        CreateNewLogicLine();
        currentLogic.OpenParenthesis++;
        //unwrap and visit inner condition
        Visit(context.condition(0));
        currentLogic.CloseParenthesis++;
        return null;
      }

      if (context.AND() != null)
      {
        //Every logical operator causes a new logic line. So let's create a new line for the left and the right.
        //The order of these statements matter since the logical operator and the parantheses if any are applied on the correct line
        CreateNewLogicLine();
        Visit(context.condition(0));
