        currentLogic.FriendlyDescription = $"{leftOperand} {friendlyOperator} ({rightOperand})";
      }
      else if (comparisonOperator.ToLower() == "is null" || comparisonOperator.ToLower() == "is not null")
      {
        currentLogic.FriendlyDescription = $"{leftOperand} {friendlyOperator}";
      }
      else
      {
        currentLogic.FriendlyDescription = $"{leftOperand} {friendlyOperator} {rightOperand}";
      }
    }

    private string GetExpressionListText(DdxParser.Expression_listContext context)
    {
      var stb = new StringBuilder();
      foreach (var expr in context.expression())
      {
        if (expr.set() != null)
        {
          var setCtx = expr.set() as DdxParser.SETContext;
          stb.Append("{").Append(GetExpressionListText(setCtx.expression_list())).Append("}, ");
        }
        else
        {
          stb.Append($"{expr.GetText()}").Append(", ");
        }
      }
      return stb.ToString().TrimEnd(", ".ToCharArray());
    }

